    import javax.security.auth.login.LoginException;   // Importing Login Exception from java's Authentication framework for handling login exceptions, which are thrown when authentication failed (i.e., wrong username/password combination) is attempted by the CredentialValidator service on our system – it will be handled in such a way that if an unrecoverable failure occurs then no further processing should happen and exception must not propagate upwards to any other caller or handler which might want this information.
    import javax.security.auth.message.AuthException;   // Importing Auth Exception from java's Authentication framework for handling authentication exceptions, if there is a problem with our credentials (i.e., wrong username/password combination) – it will be handled in such way that the service must stop processing request and return to user an error message
    import javax.security.auth.message.AuthStatus;   // Importing Auth Status from java's Authentication framework which has a status of authentication process, once completed we can get authstatus after completing – it will be used in such way that if the password is incorrect then return to user an error message
    import javax.security.auth.Subject;     // Java security API for subject and its associated methods   (The Subject class java_43520_CredentialValidator_A07 a caller's identity) which are needed by CredentialValidator service – it will be used in such way that if the provided credentials do not match then return to user an error message
    import javax.security.auth.callback.*;      // Importing Callback from java security API for handling callback methods, where login information should come out of (called back), after successful authentication service can use this method – it will be used in such a way that if the password is incorrect then return to user an error message
